    override fun Content(viewModel: BaseViewModel) {
        var showEducationalDialog by remember { mutableStateOf(false) }
        var selectedPermission by remember { mutableStateOf<PermissionInfo?>(null) }
        LibUnifiedTheme {
            Scaffold(
                topBar = {
                    TopAppBar(
                        title = {
                            Text(
                                "Permission Manager",
                                fontWeight = FontWeight.Bold
